class Solution {
    public long countGoodIntegers(int n, int k) {
        long total = 0;
        int[] freq = new int[10];
        int[] digits = new int[n];
        for (int mask = 0; mask < (1 << (n / 2)); mask++) {
            Arrays.fill(freq, 0);
            int len = 0;
            for (int i = 0; i < n / 2; i++) {
                int d = (mask >> (i * 4)) & 15;
                if (d == 0) continue;
                freq[d]++;
                digits[len++] = d;
            }
            for (int mid = 0; mid < 10; mid++) {
                if (n % 2 == 1) {
                    freq[mid]++;
                }
                long ways = 0;
                for (int first = 1; first < 10; first++) {
                    if (freq[first] == 0) continue;
                    freq[first]--;
                    ways += dfs(0, 0, n, k, freq, first);
                    freq[first]++;
                }
                total += ways;
                if (n % 2 == 1) {
                    freq[mid]--;
                }
            }
        }
        return total;
    }

    private long dfs(int pos, int rem, int n, int k, int[] freq, int first) {
        if (pos == n - 1) {
            return rem == 0 ? 1 : 0;
        }
        long res = 0;
        for (int d = 0; d < 10; d++) {
            if (freq[d] == 0) continue;
            freq[d]--;
            res += dfs(pos + 1, (rem * 10 + d) % k, n, k, freq, first);
            freq[d]++;
        }
        return res;
    }
}
